'use client';

import type * as React from 'react';

import {cn} from '@/lib/utils';

import * as ResizablePrimitive from 'react-resizable-panels';

/**
 * A container for resizable panels that can be arranged horizontally or vertically.
 * Wraps `react-resizable-panels` `Group` — all `GroupProps` are forwarded.
 *
 * ### Component Props
 *
 * | Prop                | Type                                        | Default |
 * | :------------------ | :------------------------------------------ | :------ |
 * | _orientation_       | `"horizontal" \| "vertical"`               | -       |
 * | _defaultLayout_     | `Layout`                                    | -       |
 * | _onLayoutChanged_   | `(layout: Layout) => void`                  | -       |
 * | _onLayoutChange_    | `(layout: Layout) => void`                  | -       |
 * | _disabled_          | `boolean`                                   | `false` |
 * | _disableCursor_     | `boolean`                                   | `false` |
 * | _id_                | `string \| number`                          | -       |
 * | _groupRef_          | `Ref<GroupImperativeHandle \| null>`        | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ResizablePanelGroup orientation="horizontal">
 *   <ResizablePanel defaultSize={50}>
 *     <div>Panel 1</div>
 *   </ResizablePanel>
 *   <ResizableHandle />
 *   <ResizablePanel defaultSize={50}>
 *     <div>Panel 2</div>
 *   </ResizablePanel>
 * </ResizablePanelGroup>
 * ```
 */
function ResizablePanelGroup({
  className,
  ...props
}: React.ComponentProps<typeof ResizablePrimitive.Group>) {
  return (
    <ResizablePrimitive.Group
      data-slot="resizable-panel-group"
      className={cn(
        'flex h-full w-full data-[panel-group-direction=vertical]:flex-col',
        className
      )}
      {...props}
    />
  );
}

/**
 * An individual resizable panel within a ResizablePanelGroup.
 * Wraps `react-resizable-panels` `Panel` — all `PanelProps` are forwarded.
 *
 * ### Component Props
 *
 * | Prop                   | Type                                                          | Default |
 * | :--------------------- | :------------------------------------------------------------ | :------ |
 * | _defaultSize_          | `number \| string`                                            | -       |
 * | _minSize_              | `number \| string`                                            | -       |
 * | _maxSize_              | `number \| string`                                            | -       |
 * | _collapsible_          | `boolean`                                                     | `false` |
 * | _collapsedSize_        | `number \| string`                                            | -       |
 * | _onResize_             | `(size: number, prevSize: number \| undefined) => void`       | -       |
 * | _id_                   | `string \| number`                                            | -       |
 * | _disabled_             | `boolean`                                                     | `false` |
 * | _groupResizeBehavior_  | `"preserve-relative-size" \| "preserve-pixel-size"`           | -       |
 * | _panelRef_             | `Ref<PanelImperativeHandle \| null>`                          | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ResizablePanel defaultSize={50} minSize={20}>
 *   <div>Resizable content</div>
 * </ResizablePanel>
 * ```
 */
function ResizablePanel({
  ...props
}: React.ComponentProps<typeof ResizablePrimitive.Panel>) {
  return <ResizablePrimitive.Panel data-slot="resizable-panel" {...props} />;
}

/**
 * A draggable handle between resizable panels that allows the user to resize them.
 * Wraps `react-resizable-panels` `Separator` — all `SeparatorProps` are forwarded.
 *
 * ### Component Props
 *
 * | Prop          | Type                               | Default |
 * | :------------ | :--------------------------------- | :------ |
 * | _withHandle_  | `boolean`                          | -       |
 * | _disabled_    | `boolean`                          | `false` |
 * | _id_          | `string \| number`                 | -       |
 * | _elementRef_  | `Ref<HTMLDivElement>`              | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ResizableHandle withHandle />
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 2.1.1 Keyboard — separator is focusable and resized via Arrow/Home/End keys (handled by `react-resizable-panels`).
 * @wcag 2.4.7 Focus Visible — focus indicator painted via `focus-visible:ring-3 focus-visible:ring-ring` (box-shadow) plus `focus-visible:outline-1 focus-visible:outline-ring` (CSS outline) so it remains visible even when adjacent panels clip overflow.
 * @wcag 1.4.11 Non-text Contrast — `ring-ring` / `outline-ring` resolve to the DDS `--ring` token which meets 3:1 against `bg-background` / `bg-card` panel surfaces in light, dark, and high-contrast themes.
 * @wcag 4.1.2 Name, Role, Value — separator exposes `role="separator"` with `aria-orientation` and `aria-valuemin`/`aria-valuemax`/`aria-valuenow` from `react-resizable-panels`.
 */
function ResizableHandle({
  withHandle,
  className,
  ...props
}: React.ComponentProps<typeof ResizablePrimitive.Separator> & {
  withHandle?: boolean;
}) {
  return (
    <ResizablePrimitive.Separator
      data-slot="resizable-handle"
      className={cn(
        'relative flex w-px items-center justify-center bg-border outline-none after:absolute after:inset-y-0 after:left-1/2 after:w-1 after:-translate-x-1/2 focus-visible:ring-3 focus-visible:ring-ring focus-visible:outline-1 focus-visible:outline-ring data-[panel-group-direction=vertical]:h-px data-[panel-group-direction=vertical]:w-full data-[panel-group-direction=vertical]:after:left-0 data-[panel-group-direction=vertical]:after:h-1 data-[panel-group-direction=vertical]:after:w-full data-[panel-group-direction=vertical]:after:translate-x-0 data-[panel-group-direction=vertical]:after:-translate-y-1/2 [&[data-panel-group-direction=vertical]>div]:rotate-90',
        className
      )}
      {...props}
    >
      {withHandle && (
        <div className="z-raised flex h-6 w-1 shrink-0 rounded bg-border" />
      )}
    </ResizablePrimitive.Separator>
  );
}

export {ResizableHandle, ResizablePanel, ResizablePanelGroup};
